Node *generateBFSBinaryTree(vector<int> input_nodes) {
    Node *root = new Node{input_nodes[0]};
    queue<Node *> que;
    que.push(root);
    for (int i = 1; i < input_nodes.size(); ++i) {
        Node *node = new Node{input_nodes[i]};
        Node *par = que.front();
        que.pop();
        if (!par->left) {
            par->left = node;
        }
        else {
            par->right = node;
        }
        que.push(node);
    }
    return root;
}

public class BinarySearch2D
{
    public void Search(int[,] matrix, int target)
    {
        if (matrix == null || matrix.GetLength(0) == 0 || matrix.GetLength(1) == 0) 
            return;

        int rows = matrix.GetLength(0);
        int columns = matrix.GetLength(1);

        int row = 0;
        int column = columns - 1;

        while (row < rows && column >= 0)
        {
            if (matrix[row, column] == target)
            {
                Console.WriteLine($"Target found at row: {row} and column: {column}");
                return;
            }
            else if (matrix[row, column] > target)
            {
                column--;
            }
            else
            {
                row++;
            }
        }
    }
}

