class Stack: 
	def __init__(self): 
		self.stack = [] 

	# This method adds an element at the top of the stack 
	def push(self, item): 
		self.stack.append(item) 

	# This method removes the topmost element and returns it 
	def pop(self): 
		if self.is_empty(): 
			return None
		return self.stack.pop() 

	# This method returns the topmost element without removing it 
	def peek(self): 
		if self.is_empty(): 
			return None
		return self.stack[-1] 

	# This method returns true or false depending on whether the stack is empty or not 
	def is_empty(self): 
		return len(self.stack) == 0

public class BST { 

    /* Class containing left and right child of current node and key value*/
    class Node { 
        int key; 
        Node left, right; 

        public Node(int item) { 
            key = item; 
            left = right = null; 
        } 
    } 

    // Root of BST 
    Node root; 

    // Constructor 
    BST() {  
        root = null;  
    } 

    // This method mainly calls insertRec() 
    void insert(int key) { 
       root = insertRec(root, key); 
    } 

    // A recursive function to insert a new key in BST 
    Node insertRec(Node root, int key) { 

        // If the tree is empty, return a new node 
        if (root == null) { 
            root = new Node(key); 
            return root; 
        } 

        // Otherwise, recur down the tree 
        if (key < root.key) 
            root.left = insertRec(root.left, key); 
        else if (key > root.key) 
            root.right = insertRec(root.right, key); 

        // return the (unchanged) node pointer 
        return root; 
    } 

}

// Java Program to convert binary tree to doubly linked list 
public class BinaryTreeToDLL { 

    Node root; 

    // A simple recursive function to convert a given Binary tree 
    // to Doubly Linked List 
    Node BTTDLL(Node root) { 

        // Base case 
        if (root == null) 
            return root; 

        // Convert the left subtree and link to root 
        if (root.left != null) { 

            // Convert the left subtree 
            Node left = BTTDLL(root.left); 

            // Find inorder predecessor. After this loop, left 
            // will point to the inorder predecessor 
            for (; left.right != null; left = left.right); 

            // Make root as next of the predecessor 
            left.right = root; 

            // Make predecssor as previous of root 
            root.left = left; 
        } 

        // Convert the right subtree and link to root 
        if (root.right != null) { 

            // Convert the right subtree 
            Node right = BTTDLL(root.right); 

            // Find inorder successor. After this loop, right 
            // will point to the inorder successor 
            for (; right.left != null; right = right.left); 

            // Make root as previous of successor 
            right.left = root; 

            // Make successor as next of root 
            root.right = right; 
        } 

        return root; 
    } 
}

import java.util.Scanner;

public class TicTacToe {

    public static char[][] board = new char[3][3];
    public static boolean playerX;
    public static Scanner scan;

    public static void main(String[] args) {
        scan = new Scanner(System.in);
        playerX = true;
        initializeBoard();

        while(true) {
            printBoard();
            nextMove(playerX);
            if(checkWinner()) {
                break;
            }
            playerX = !playerX;
        }

    }

    public static void initializeBoard() {
        for(int i=0;i<3;i++)
            for(int j=0;j<3;j++)
                board[i][j] = '-';
    }

    public static void printBoard() {
        System.out.println("-------------");
        for (int i = 0; i < 3; i++) {
            System.out.print("| ");
            for (int j = 0; j < 3; j++) {
                System.out.print(board[i][j] + " | ");
            }
            System.out.println();
        }
        System.out.println("-------------");
    }

    public static void nextMove(boolean player) {
        if(player)
            System.out.print("Player X, enter your move row,col: ");
        else
            System.out.print("Player O, enter your move row,col: ");

        int row = scan.nextInt() - 1;
        int col = scan.nextInt() - 1;
        board[row][col] = player ? 'X' : 'O';
    }

    public static boolean checkWinner() {
        // Horizontal win
        for(int i=0;i<3;i++) {
            if(board[i][0] == board[i][1] && board[i][1] == board[i][2])
                return true;
        }

        // Vertical win
        for(int j=0;j<3;j++) {
            if(board[0][j] == board[1][j] && board[1][j] == board[2][j])
                return true;
        }

        // Diagonal win
        if(board[0][0] == board[1][1] && board[1][1] == board[2][2])
            return true;
        if(board[2][0] == board[1][1] && board[1][1] == board[0][2])
            return true;

        return false;
    }

}

