import java.util.HashMap;

public class Anagram { 

    // Utility method to check whether two strings are anagram or not 
    static boolean areAnagram(String A, String B) { 

        // If length of both strings is not same, then they can't be anagram
        if (A.length() != B.length()) 
            return false; 

        // Make a copy of string
        A = A.toLowerCase(); 
        B = B.toLowerCase(); 

        // Create a hash map
        HashMap<Character, Integer> map = new HashMap<>(); 

        // Iterate through both strings and increment count
        // in hash map 
        for (int i = 0; i < A.length(); i++) { 
            char ch = A.charAt(i); 

            if (map.containsKey(ch)) {
                int f = map.get(ch); 
                f++; 
                map.put(ch, f); 
            } else {
                map.put(ch, 1); 
            }
        } 

        for (int i = 0; i < B.length(); i++) {
            char ch = B.charAt(i); 
            if (map.containsKey(ch)) {
                int f = map.get(ch); 

                // If char is not present, then by default 
                // f would be 0
                if (f == 0) 
                    return false; 

                f--; 
                map.put(ch, f); 
            } else {
                return false; 
            }
        }
        return true;
    } 

    // Driver code 
    public static void main (String[] args) throws java.lang.Exception { 
        String A = "listen";
        String B = "silent";
        if (areAnagram(A, B)) {
            System.out.println("The two strings are anagrams of each other.");
        } else {
            System.out.println("The two strings are not anagrams of each other.");
        }
    } 
}

def levenshtein_distance(str1, str2):
 # Create a matrix for storing the distances
 m = [[0 for x in range(len(str2) + 1)] for x in range(len(str1) + 1)]
 # Mark the first Edit Distance value as 0
 m[0][0] = 0

 # Iterate over the matrix 
 for i in range(0, len(str1) + 1):
  for j in range(0, len(str2) + 1):
   # If we are at the first row or first col, mark the cells with corresponding numbers
   if i == 0:
    m[i][j] = j
   elif j == 0:
    m[i][j] = i
   # Otherwise, calculate the distance according to the  formula
   else:
    if str1[i-1] == str2[j-1]:
     m[i][j] = m[i-1][j-1]
    else:
     m[i][j] = min(m[i-1][j], m[i-1][j-1], m[i][j-1]) + 1

 # Return the last element in the matrix, which is the Levenshtein Distance
 return m[-1][-1]

public static ArrayList<String> allPermutations(String inputString){
    ArrayList<String> permutations = new ArrayList<>();
    if (inputString.length() == 0) {
        permutations.add("");
        return permutations;
    }

    char first = inputString.charAt(0);
    String remainder = inputString.substring(1);
    ArrayList<String> words = allPermutations(remainder);
    for (String word : words) {
        for (int j = 0; j <= word.length(); j++) {
            permutations.add(insertCharAt(word, first, j));
        }
    }
    return permutations;
}

public static String insertCharAt(String word, char c, int i) {
    String start = word.substring(0, i);
    String end = word.substring(i);
    return start + c + end;
}

