class DoublyLinkedList { 
    Node head; 

    // Inserts a new Node at front of the list 
    public void push(int new_data) 
    { 
        Node new_node = new Node(new_data); 

        new_node.next = head; 
        new_node.previous = null; 

        if (head != null) 
            head.previous = new_node; 

        head = new_node; 
    } 

    // Delete a node from the list 
    void deleteNode(Node node_ptr) 
    { 
        // If node to be deleted is head node 
        if (head == node_ptr) 
            head = node_ptr.next; 

        // Change next only if node to be deleted  
        // is NOT the last node 
        if (node_ptr.next != null) 
            node_ptr.next.previous = node_ptr.previous; 

        // Change prev only if node to be deleted  
        // is NOT the first node 
        if (node_ptr.previous != null) 
            node_ptr.previous.next = node_ptr.next; 
    } 

    // Display linked list 
    public void display() 
    { 
        Node last = null; 
        System.out.println("Doubly Linked List in forward \n"); 
        while (head != null) { 
            System.out.print(head.data + " <=> "); 
            last = head; 
            head = head.next; 
        } 
        System.out.println("null\n"); 

        System.out.println("Doubly Linked List in reverse \n"); 
        while (last != null) { 
            System.out.print(last.data + " <=> "); 
            last = last.previous; 
        } 
        System.out.println("null\n"); 
    } 
}

public class BinaryTree { 

    // Root of Binary Tree 
    Node root; 

    // Function to print binary tree in level order 
    void printLevelOrder() { 
        int h = height(root); 
        int i; 
        for (i = 1; i <= h; i++) 
            levelOrder(root, i); 
    } 

    // Print nodes at a given level 
    void levelOrder(Node root, int level) { 
        if (root == null) 
            return; 
        if (level == 1) 
            System.out.print(root.data + " "); 
        else if (level > 1) { 
            levelOrder(root.left, level - 1); 
            levelOrder(root.right, level - 1); 
        } 
    } 

    // Compute the height of a tree--the number of nodes 
    // along the longest path from the root node down to 
    // the farthest leaf node 
    int height(Node root) { 
        if (root == null) 
            return 0; 
        else { 
            // compute height of each subtree 
            int lheight = height(root.left); 
            int rheight = height(root.right); 

            // use the larger one 
            if (lheight > rheight) 
                return (lheight + 1); 
            else
                return (rheight + 1); 
        } 
    } 
}

