// Function to find maximum and minimum of 
// given array 
pair <int, int> getMinMax(int arr[], int n) 
{ 
    pair <int, int> minmax; 
    int i; 

    /* If array has even number of elements then 
    initialize the first two elements as minimum  
    and maximum */
    if (n % 2 == 0) 
    { 
        if (arr[0] > arr[1])  
        { 
            minmax.second = arr[0]; 
            minmax.first = arr[1]; 
        }  
        else
        { 
            minmax.first = arr[0]; 
            minmax.second = arr[1]; 
        } 
        i = 2;  // set the startung index for loop 
    } 

    /* If array has odd number of elements then  
    initialize the first element as minimum and  
    maximum */
    else
    { 
        minmax.first = arr[0]; 
        minmax.second = arr[0]; 
        i = 1;  // set the startung index for loop 
    } 

    /* In the while loop, pick elements in pair and  
    compare the pair with max and min so far */
    while (i < n - 1)  
    { 
        if (arr[i] > arr[i + 1])  
        { 
            if(arr[i] > minmax.second) 
                minmax.second = arr[i]; 
            if(arr[i + 1] < minmax.first) 
                minmax.first = arr[i + 1]; 
        }  
        else
        { 
            if (arr[i] < minmax.first) 
                minmax.first = arr[i]; 
            if(arr[i + 1] > minmax.second) 
                minmax.second = arr[i + 1]; 
        } 
        i += 2; // Increment the index by 2 as two elements are processed in loop 
    } 
    return minmax; 
}

