// bucket sort
function bucketSort(arr) {
  let buckets = new Array(arr.length); 
  let result = []; 

  for (let i = 0; i < arr.length; i++) {
    buckets[i] = 0;
  }

  for (let i = 0; i < arr.length; i++) {
    buckets[arr[i]]++;
  }

  for (let i = 0; i < arr.length; i++) {
    while (buckets[i] > 0) {
      result.push(i);
      buckets[i]--;
    }
  }

  return result;
}

def convert_to_base(num, base): 
    """ 
    Function to convert num to a given base 
    """
    converted_string = "" 

    # Base Case 
    if num < base: 
        if num < 10: 
            return str(num) 
        else: 
            return chr(num - 10 + ord('A')) 

    rem = num % base 
    if rem < 10: 
        converted_string = str(rem) + converted_string 
    else: 
        converted_string = chr(rem - 10 + ord('A')) + converted_string 
    num = num // base 
    return convert_to_base(num, base) + converted_string

