// Function to find the kth smallest element 
int kthSmallestWComp(int arr[], int n, int k) 
{ 
    // Initialize values of left and right 
    int left = -2147483648, right = 2147483647, ans = -1; 
    while (left <= right) 
    { 
        int mid = (left + right) / 2; 
        int countLtEqMid = 0, countGtMid = 0; 

        // Loop to count total less than equal mid 
        for (int i = 0; i < n; i++) 
            if (arr[i] <= mid) 
                countLtEqMid++; 
        // Loop to count total greater than mid 
        for (int i = 0; i < n; i++) 
            if (arr[i] > mid) 
                countGtMid++; 

        if (countLtEqMid < k && k <= (countLtEqMid + countGtMid)) 
        { 
            ans = mid; 
            left = mid + 1; 
        } 
        else if (countLtEqMid >= k) 
            right = mid - 1; 

        else
            left = mid + 1; 
    } 
    return ans; 
}

function heapSort(arr) {
 let n = arr.length;

 for (let i = Math.floor(n / 2 - 1); i >= 0; i--) {
 heapify(arr, n, i);
 }

 for (let i = n - 1; i > 0; i--) {
 [arr[0], arr[i]] = [arr[i], arr[0]];
 heapify(arr, i, 0);
 }

 return arr;
}

function heapify(arr, n, i) {
 let largest = i;
 let left = 2 * i + 1;
 let right = 2 * i + 2;

 if (left < n && arr[left] > arr[largest])
 largest = left;

 if (right < n && arr[right] > arr[largest])
 largest = right;

 if (largest !== i) {
 [arr[i], arr[largest]] = [arr[largest], arr[i]];
 heapify(arr, n, largest);
 }
}

