def deserialize(serializedTree):
    q = deque(serializedTree.split(','))

    def recur(q): 
        val = q.popleft()
        if val == 'None':
            return None
        count = TreeNode(val)
        count.left = recur(q)
        count.right = recur(q)
        return count

    return recur(q)

