// Returns true if key is present in given BST 
boolean search(Node root, int key) 
{ 
    // Base Case 
    if (root == null) 
        return false; 

    // If key is present at root 
    if (root.key == key) 
        return true; 

    // Recursive calls for non-empty subtrees 
    boolean left = search(root.left, key); 
    boolean right = search(root.right, key); 

    return left || right; 
}

public int[] splitEvenSum(string inputString) {
    List<int> nums = new List<int>();

    // Split inputString at , and add elements to the list
    foreach (var num in inputString.Split(',')) {
        nums.Add(int.Parse(num));
    }

    // Initialize variables
    int targetSum = 0;
    int sum1 = 0;
    int sum2 = 0;
    List<int> list1 = new List<int>();
    List<int> list2 = new List<int>();

    // Loop through and calculate sums
    foreach (var num in nums) {
        targetSum += num;
    }
    targetSum /= 2;

    // Backtrack and find the two subarrays with the same sum
    foreach (var num in nums) {
        if (sum1 + num <= targetSum) {
            sum1 += num;
            list1.Add(num);
        } else {
            sum2 += num;
            list2.Add(num);
        }
    }

    // Return results
    int[] result = new int[2] {sum1, sum2};
    return result;
}

