def longest_common_substring(list1, list2):
    longest_substring = 0
    for i in range(len(list1)):
        for j in range(len(list2)):
            if list1[i] == list2[j]:
                current_substring = 1
                k, l = i+1, j+1
                while k < len(list1) and l < len(list2) and list1[k] == list2[l]:
                    current_substring += 1
                    k += 1
