function findFirstNonDuplicateChar(s) {
  var character = '';
  var checker = {};
  for (var i = 0; i < s.length; i++) {
    var char = s[i];
    if (checker[char]) {
      checker[char]++;
    } else {
      checker[char] = 1;
    }
  }
  for (var i = 0; i < s.length; i++) {
    var char = s[i];
    if (checker[char] === 1) {
