            int tempSum = arr[i][j] + arr[i][j+1] + arr[i][j+2] + 
                arr[i+1][j+1] + 
                arr[i+2][j] + arr[i+2][j+1] + arr[i+2][j+2]; 
            if(sum < tempSum) 
                sum = tempSum; 
        } 
    } 
    return sum; 
}

