    for char in string1:
        if char not in string1_dict:
            string1_dict[char] = 1
        else:
            string1_dict[char] += 1

    for char in string2:
        if char not in string2_dict:
            string2_dict[char] = 1
        else:
            string2_dict[char] += 1

    # Check if the dictionaries have the same entries
    for key in string1_dict:
        if key not in string2_dict:
            return False
        elif string1_dict[key] != string2_dict[key]:
