def DFS(root):
    S = []
    visited = []

    S.append(root)

    while len(S) > 0:
        node = S.pop()
        visited.append(node)

        for vertex in node.get_adjacent_vertices():
            if vertex not in visited:
                S.append(vertex)
    return visited

function flattenArray(arr, depth) {
  let result = [];

  for (let item of arr) {
    if (Array.isArray(item) && depth > 0) {
      result.push(...flattenArray(item, depth - 1)); // Recursively flatten the array
    } else {
      result.push(item);
    }
  }

  return result;
}

