def fibonacci(n):
    if n == 0:
        return []
    elif n == 1:
        return [0]
    elif n == 2:
        return [0, 1]
    elif n > 2:
        fib_nums = [0, 1]
        for i in range(2, n):
            fib_nums.append(fib_nums[i-1] + fib_nums[i-2])
        return fib_nums

