// Given a pointer to a node, delete the node from the linked list
// Do not return anything, changes are done in place. 
void deleteNode(Node *node)
{
    Node* temp = node;
    Node* next = temp->next;
    node->data = next->data;
    node->next = next->next;
    free(next);
}

